detailed_optimizations.code_changes:
将三重循环改为分块循环（示例，块大小需按 L1/L2/LLC 调参）：

// 选择块大小（示例）
const int Ti=64, Tj=128, Tk=64;
for (int ii=0; ii<_PB_NI; ii+=Ti)
  for (int jj=0; jj<_PB_NJ; jj+=Tj) {
    // 先对 C 子块做 beta 缩放
    for (int i=ii; i<min(ii+Ti,_PB_NI); ++i)
      for (int j=jj; j<min(jj+Tj,_PB_NJ); ++j)
        C[i][j] *= beta;

    for (int kk=0; kk<_PB_NK; kk+=Tk)
      for (int i=ii; i<min(ii+Ti,_PB_NI); ++i)
        for (int k=kk; k<min(kk+Tk,_PB_NK); ++k) {
          DATA_TYPE aik = alpha * A[i][k];
          // j 连续，利于向量化
          for (int j=jj; j<min(jj+Tj,_PB_NJ); ++j)
            C[i][j] += aik * B[k][j];
        }
  }

在最内层对 j 做 4/8/16 元素寄存器累加（配合编译器自动向量化或显式 SIMD）。示例（以 8 为例，伪代码）：

for (int i=...)
  for (int j=jj; j<jend; j+=8) {
    vec c = load(C[i][j..j+7]) * beta; // 或先整体 beta 缩放后这里直接 load
    for (int k=kk; k<kend; ++k) {
      scalar aik = alpha*A[i][k];
      vec b = load(B[k][j..j+7]);
      c = fma(aik, b, c);
    }
    store(C[i][j..j+7], c);
  }

若保留原结构，也至少将 A[i][k] 提前：
DATA_TYPE aik = alpha * A[i][k];
for (j=0; j<_PB_NJ; ++j) C[i][j] += aik * B[k][j];

1) 提前提取 aik（如上）减少内层标量加载；2) 为指针添加 restrict（若可改接口）：

void kernel_gemm(...,
  DATA_TYPE (* restrict C)[NJ],
  const DATA_TYPE (* restrict A)[NK],
  const DATA_TYPE (* restrict B)[NJ])

3) 加向量化提示（视编译器）：
#pragma omp simd
for (j=jj; j<jend; ++j) C[i][j] += aik * B[k][j];

4) 确保对齐分配（PolyBench 通常已对齐，但可确认/强化）。

推荐对外层 tile 并行（更利于 NUMA/缓存局部性）：

#pragma omp parallel for collapse(2) schedule(static)
for (int ii=0; ii<_PB_NI; ii+=Ti)
  for (int jj=0; jj<_PB_NJ; jj+=Tj) {
    ... // 该 tile 内只写 C[ii:ii+Ti, jj:jj+Tj]，无数据竞争
  }

若不分块，至少：
#pragma omp parallel for schedule(static)
for (int i=0; i<_PB_NI; ++i) { ... }

将 i-j-k 改为 i-k-j（或 i-k 外层、j 内层），使 B[k][j] 在 j 上连续访问；同时对 tmp[i][j] 做寄存器累加并一次性写回。示例：

for (int i=0;i<_PB_NI;i++)
  for (int j=0;j<_PB_NJ;j++) tmp[i][j]=0;
for (int i=0;i<_PB_NI;i++) {
  for (int k=0;k<_PB_NK;k++) {
    DATA_TYPE a = alpha * A[i][k];
    #pragma omp simd
    for (int j=0;j<_PB_NJ;j++) {
      tmp[i][j] += a * B[k][j];
    }
  }
}

并建议为 A/B/tmp 指针加 restrict（若可）以帮助向量化：
void kernel_2mm(..., DATA_TYPE (*restrict tmp)[NJ], ...)

对 i/j/k 做分块，典型选择：Ti≈(L2可容纳的A块行数)、Tj≈(L2可容纳的B块列数)、Tk≈共享维度块。示例（伪代码，需按 NI/NJ/NK 宏展开）：

const int Ti=32, Tj=128, Tk=32;
for (int ii=0; ii<_PB_NI; ii+=Ti)
  for (int kk=0; kk<_PB_NK; kk+=Tk)
    for (int jj=0; jj<_PB_NJ; jj+=Tj)
      for (int i=ii; i<min(ii+Ti,_PB_NI); i++)
        for (int k=kk; k<min(kk+Tk,_PB_NK); k++) {
          DATA_TYPE a = alpha*A[i][k];
          #pragma omp simd
          for (int j=jj; j<min(jj+Tj,_PB_NJ); j++)
            tmp[i][j] += a*B[k][j];
        }

并配合编译选项：-O3 -march=native -ffast-math（若允许）

当前先 D[i][j]*=beta 再 k 累加。可改为寄存器中初始化为 beta*D[i][j]，避免额外写回与潜在写分配开销：

for (int i=0;i<_PB_NI;i++)
  for (int j=0;j<_PB_NL;j++) {
    DATA_TYPE acc = beta * D[i][j];
    #pragma omp simd reduction(+:acc) // 对标量不合适；更推荐 j 向量化
    for (int k=0;k<_PB_NJ;k++) acc += tmp[i][k]*C[k][j];
    D[i][j] = acc;
  }

更进一步：改为 i-k-j 顺序以让 C[k][j] 在 j 上连续：
for i
  for j D[i][j]=beta*D[i][j];
for i
  for k
    for j D[i][j]+=tmp[i][k]*C[k][j];

与热点1同理，对 (i,k,j) 做块化，优先让 j 为最内层以连续访问 C[k][j] 与 D[i][j]：

const int Ti=32, Tj=128, Tk=32;
for (int ii=0; ii<_PB_NI; ii+=Ti)
  for (int kk=0; kk<_PB_NJ; kk+=Tk)
    for (int jj=0; jj<_PB_NL; jj+=Tj)
      for (int i=ii; i<min(ii+Ti,_PB_NI); i++)
        for (int k=kk; k<min(kk+Tk,_PB_NJ); k++) {
          DATA_TYPE t = tmp[i][k];
          #pragma omp simd
          for (int j=jj; j<min(jj+Tj,_PB_NL); j++)
            D[i][j] += t * C[k][j];
        }

并在进入该阶段前做一次 D*=beta（或在块内初始化）。

方案A（推荐，最少代码）：用 BLAS 替换三重循环。
// 需要把 PolyBench 2D 宏展开为连续内存并提供 leading dimensions
// E(ni x nj) = A(ni x nk) * B(nk x nj)
// cblas_dgemm(CblasRowMajor, CblasNoTrans, CblasNoTrans,
//             ni, nj, nk, 1.0, &A[0][0], nk, &B[0][0], nj, 0.0, &E[0][0], nj);

方案B（保留手写）：分块并调整循环次序以提升 B 的复用。
const int Ti=64, Tj=64, Tk=64;
#pragma omp parallel for collapse(2) schedule(static)
for (int ii=0; ii<_PB_NI; ii+=Ti)
  for (int jj=0; jj<_PB_NJ; jj+=Tj) {
    for (int i=ii; i<min(ii+Ti,_PB_NI); ++i)
      for (int j=jj; j<min(jj+Tj,_PB_NJ); ++j)
        E[i][j]=0;
    for (int kk=0; kk<_PB_NK; kk+=Tk)
      for (int i=ii; i<min(ii+Ti,_PB_NI); ++i)
        for (int k=kk; k<min(kk+Tk,_PB_NK); ++k) {
          DATA_TYPE aik = A[i][k];
          #pragma omp simd
          for (int j=jj; j<min(jj+Tj,_PB_NJ); ++j)
            E[i][j] += aik * B[k][j];
        }
  }
要点：把 j 放到最内层并对 j 向量化；对 (ii,jj) 分块让 B[k][j] 在 L1/L2 内复用；对 (ii,jj) 并行避免写冲突。

方案A：BLAS
// F(nj x nl) = C(nj x nm) * D(nm x nl)
// cblas_dgemm(RowMajor, NoTrans, NoTrans, nj, nl, nm, 1.0, &C[0][0], nm, &D[0][0], nl, 0.0, &F[0][0], nl);

方案B：若不分块，至少转置 D 以改善访问（把 D[k][j] 的列访问变为行访问）：
// 预处理一次：DT(nl x nm)
for (int k=0;k<_PB_NM;++k)
  for (int j=0;j<_PB_NL;++j)
    DT[j][k]=D[k][j];
// 计算：F[i][j]+=C[i][k]*DT[j][k]
for (int i=0;i<_PB_NJ;++i)
  for (int j=0;j<_PB_NL;++j){
    DATA_TYPE sum=0;
    #pragma omp simd reduction(+:sum)
    for (int k=0;k<_PB_NM;++k)
      sum += C[i][k]*DT[j][k];
    F[i][j]=sum;
  }
更优：结合分块（同热点1的 ii/jj/kk 结构）。

方案A：BLAS
// G(ni x nl) = E(ni x nj) * F(nj x nl)
// cblas_dgemm(RowMajor, NoTrans, NoTrans, ni, nl, nj, 1.0, &E[0][0], nj, &F[0][0], nl, 0.0, &G[0][0], nl);

方案B：手写分块同热点1（把 j 最内层，k 次内层，块内复用 F[k][j]）。

方案C（hard，高级）：链式乘法融合/重排以减少写回 E/F（例如用分块流水：计算 E_block 后立刻参与 G_block 累加，避免 E 全量落内存；同理对 F）。需要三层块调度与临时缓冲，复杂且易受容量限制。

1) 预先构造 AT[k][j] = A[j][k]（尺寸 MxN），使内层 j 访问 AT[k][j] 连续：

// allocate AT[M][N]
POLYBENCH_2D_ARRAY_DECL(AT,DATA_TYPE,M,N,m,n);
for (int j=0;j<n;j++)
  for (int k=0;k<m;k++)
    AT[k][j]=A[j][k];

// kernel: for i: scale C; then for k: for j<=i: C[i][j]+=alpha*A[i][k]*AT[k][j]
for (i=0;i<n;i++) {
  for (j=0;j<=i;j++) C[i][j]*=beta;
  for (k=0;k<m;k++) {
    DATA_TYPE aik = A[i][k];
    for (j=0;j<=i;j++)
      C[i][j] += alpha * aik * AT[k][j];
  }
}

2) 更推荐：直接调用高性能 BLAS（如 OpenBLAS/MKL/BLIS）的 syrk：
// C := alpha*A*A^T + beta*C (lower)
// cblas_dsyrk(CblasRowMajor, CblasLower, CblasNoTrans, n, m, alpha, &A[0][0], m, beta, &C[0][0], n);

示例：对 j 做块化，让 C(i, j..jB) 在寄存器/缓存中累加，减少写回频率，并利于 SIMD。

const int JB = 64; // 依据缓存/向量宽度调参
for (int i=0;i<n;i++) {
  for (int jb=0; jb<=i; jb+=JB) {
    int jend = (jb+JB-1<=i)? (jb+JB-1): i;
    // scale block once
    for (int j=jb;j<=jend;j++) C[i][j] *= beta;

    for (int k=0;k<m;k++) {
      DATA_TYPE aik = A[i][k];
      // pragma to help vectorization on contiguous C[i][j]
      #pragma omp simd
      for (int j=jb;j<=jend;j++) {
        C[i][j] += alpha * aik * A[j][k];
      }
    }
  }
}

进一步：若配合 AT（上一个优化）则内层 A[j][k] 改为 AT[k][j]，向量化更稳定。

并行 i（每个线程写不同的 C[i][0..i]，无数据竞争）：

#pragma omp parallel for schedule(static)
for (int i=0;i<n;i++) {
  for (int j=0;j<=i;j++) C[i][j] *= beta;
  for (int k=0;k<m;k++) {
    DATA_TYPE aik = A[i][k];
    #pragma omp simd
    for (int j=0;j<=i;j++)
      C[i][j] += alpha * aik * A[j][k];
  }
}

若 i 负载不均（小 i 工作少），可用 schedule(guided) 或对 i 做块化后静态分配。
NUMA：在 init_array 中用并行 first-touch 初始化 A/C。

将 i-k-j 改为 i-j-k，使每个 C[i][j] 在寄存器中完成 beta 缩放与 k 累加，最后一次性写回；同时预计算 aalpha=alpha, 或将 alpha 融合到 A/B 的乘法中。

示例：
for (int i=0;i<_PB_N;i++) {
  for (int j=0;j<=i;j++) {
    DATA_TYPE cij = C[i][j]*beta;
    for (int k=0;k<_PB_M;k++) {
      cij += alpha*(A[j][k]*B[i][k] + B[j][k]*A[i][k]);
    }
    C[i][j]=cij;
  }
}

对 i-j 形成块（Ti,Tj），对 k 形成块 Tk；在每个块内复用 A/B 的 k-panel，减少对 A[j][k],B[j][k] 的重复从内存加载。可选：对 A_block(j,k) 与 B_block(j,k) 做临时打包为连续内存（pack）以提升带宽与SIMD。

伪代码：
for (ii=0; ii<N; ii+=Ti)
 for (jj=0; jj<=ii; jj+=Tj)
  for (kk=0; kk<M; kk+=Tk) {
    // 可选 pack A[jj:jj+Tj][kk:kk+Tk], B[...] 到连续缓冲
    for (i=ii; i<min(ii+Ti,N); i++)
      for (j=jj; j<min(jj+Tj,i+1); j++) {
        DATA_TYPE cij = (kk==0)? C[i][j]*beta : C[i][j];
        for (k=kk; k<min(kk+Tk,M); k++)
          cij += alpha*(A[j][k]*B[i][k] + B[j][k]*A[i][k]);
        C[i][j]=cij;
      }
  }

1) 将 A[i][k], B[i][k] 在 j 循环外（或 k 循环内）提升为标量，避免重复加载；2) 为 A/B/C 指针添加 restrict（若允许）并确保对齐；3) 在 k 内循环上尝试向量化（更适合 i-j-k 版本），或在分块后对 k 维做 #pragma omp simd。

示例（在 i-j-k 结构中）：
for (int k=0;k<M;k++) {
  // 编译器更易向量化 k
}
并在函数签名中（若可改）：
void kernel_syr2k(..., DATA_TYPE (* restrict C)[N], DATA_TYPE (* restrict A)[M], DATA_TYPE (* restrict B)[M])

并行化 i（或 ii 块）维度；每个线程写不同的 C[i][j] 区域无冲突。注意 j<=i 的三角形边界，推荐按 i 或按块并行。

示例：
#pragma omp parallel for schedule(static)
for (int i=0;i<_PB_N;i++) {
  for (int j=0;j<=i;j++) {
    DATA_TYPE cij = C[i][j]*beta;
    for (int k=0;k<_PB_M;k++)
      cij += alpha*(A[j][k]*B[i][k] + B[j][k]*A[i][k]);
    C[i][j]=cij;
  }
}

将计算改为先清零sum，然后对每个s取a=A[r][q][s]，再对p做sum[p]+=a*C4[s][p]。这样C4按行连续访问，sum顺序写，易SIMD。

示例:
for (p=0;p<np;p++) sum[p]=0;
for (s=0;s<np;s++) {
  DATA_TYPE a = A[r][q][s];
  #pragma omp simd
  for (p=0;p<np;p++)
    sum[p] += a * C4[s][p];
}
for (p=0;p<np;p++) A[r][q][p]=sum[p];

对p做tile，例如PT=32/64：
for (p0=0;p0<np;p0+=PT){
  DATA_TYPE acc[PT]; // 若PT为编译期常量可完全寄存器化/向量化
  for (pp=0;pp<PT && p0+pp<np;pp++) acc[pp]=0;
  for (s=0;s<np;s++){
    DATA_TYPE a=A[r][q][s];
    #pragma omp simd
    for (pp=0;pp<PT && p0+pp<np;pp++)
      acc[pp]+=a*C4[s][p0+pp];
  }
  for (pp=0;pp<PT && p0+pp<np;pp++) A[r][q][p0+pp]=acc[pp];
}
这样可完全去掉sum数组(或仅作为可选缓冲)，减少一次sum写+一次sum读的流量。

并行(r,q)维度，避免sum共享：
#pragma omp parallel for collapse(2) private(p,s) schedule(static)
for (r=0;r<nr;r++)
  for (q=0;q<nq;q++) {
    // 使用上面“去sum数组”的acc tile，或声明sum为线程私有缓冲
  }
若仍使用sum数组：改为在parallel区域内分配 thread-local sum (malloc/alloca) 或使用PolyBench提供的临时数组宏。

1) 提前取列指针并加 restrict：
```cpp
for (int k=0;k<_PB_N;k++){
  DATA_TYPE * __restrict Ak = &A[0][k];
  DATA_TYPE nrm = 0;
  #pragma omp simd reduction(+:nrm)
  for (int i=0;i<_PB_M;i++) nrm += Ak[i*_PB_N]*Ak[i*_PB_N];
  R[k][k] = sqrt(nrm);
  ...
}
```
2) 若允许依赖库：用 cblas_dnrm2(m, &A[0][k], N)（stride=N）。
3) 编译器选项：-O3 -ffast-math -march=native（或对应平台）并确保 A 行主序连续。

```cpp
DATA_TYPE inv = (DATA_TYPE)1.0 / R[k][k];
DATA_TYPE * __restrict Qk = &Q[0][k];
DATA_TYPE * __restrict Ak = &A[0][k];
#pragma omp simd
for (int i=0;i<_PB_M;i++)
  Qk[i*_PB_N] = Ak[i*_PB_N] * inv;
```
（保持 stride=N 的列访问；若可改变布局见后续 data_layout 建议。）

方案A（纯代码，块化+并行）：
```cpp
const int JB = 32; // 依据缓存/寄存器调
for (int j0=k+1; j0<_PB_N; j0+=JB){
  int j1 = (j0+JB<_PB_N)? j0+JB : _PB_N;
  // 初始化 R[k][j]
  for(int j=j0;j<j1;j++) R[k][j]=0;
  for (int i=0;i<_PB_M;i++){
    DATA_TYPE q = Q[i][k];
    #pragma omp simd
    for(int j=j0;j<j1;j++)
      R[k][j] += q * A[i][j];
  }
}
```
方案B（BLAS）：把 A 的子矩阵 A[:,k+1:] 视为 (m x (n-k-1))，计算 r = Q[:,k]^T * A_sub，可用 cblas_dgemv 或 dgemm(1 x m) * (m x nb)。

推荐与上一个热点配套的 j-block，并在得到 R[k][j] 后对同一块做更新：
```cpp
for (int j0=k+1; j0<_PB_N; j0+=JB){
  int j1 = min(j0+JB,_PB_N);
  // 1) 计算 R[k][j0:j1)
  for(int j=j0;j<j1;j++) R[k][j]=0;
  for(int i=0;i<_PB_M;i++){
    DATA_TYPE q = Q[i][k];
    #pragma omp simd
    for(int j=j0;j<j1;j++) R[k][j] += q * A[i][j];
  }
  // 2) 更新 A[:,j0:j1)
  for(int i=0;i<_PB_M;i++){
    DATA_TYPE q = Q[i][k];
    #pragma omp simd
    for(int j=j0;j<j1;j++) A[i][j] -= q * R[k][j];
  }
}
```
并行：
```cpp
#pragma omp parallel for schedule(static)
for (int j0=...)
  ... // 每个线程处理不同 j-block
```
注意：k 循环仍串行，但每个 k 内 j-block 可并行。
